mapper.select:
SELECT o.*, d.name as dish_name, d.category_id, u.username, u.nickname FROM order_record o LEFT JOIN dish d ON o.dish_id = d.id LEFT JOIN user u ON o.user_id = u.id
AND o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.order_date DESC, o.created_at DESC

SELECT d.id as dishId, d.name as dishName, COUNT(*) as orderCount FROM order_record o LEFT JOIN dish d ON o.dish_id = d.id
AND o.user_id = #{userId}
GROUP BY d.id, d.name ORDER BY orderCount DESC LIMIT 10
